const text = $json.bluesky?.text;
if (typeof text !== 'string' || text.trim().length === 0) {
  throw new Error('Bluesky text is required');
}
if ([...text].length > 300) {
  throw new Error('Bluesky text exceeds 300 characters');
}

function utf8Index(value, utf16Index) {
  const prefix = value.slice(0, utf16Index);
  if (typeof TextEncoder !== 'undefined') {
    return new TextEncoder().encode(prefix).byteLength;
  }
  if (typeof Buffer !== 'undefined') {
    return Buffer.byteLength(prefix, 'utf8');
  }
  return unescape(encodeURIComponent(prefix)).length;
}

function parseUrlFacets(value) {
  const facets = [];
  const urlPattern = /https?:\/\/[^\s<>"']+/g;
  let match;

  while ((match = urlPattern.exec(value)) !== null) {
    const uri = match[0].replace(/[),.!?;:]+$/g, '');
    if (!/^https?:\/\//.test(uri)) {
      continue;
    }

    const start = match.index;
    const end = start + uri.length;
    facets.push({
      index: {
        byteStart: utf8Index(value, start),
        byteEnd: utf8Index(value, end)
      },
      features: [
        {
          $type: 'app.bsky.richtext.facet#link',
          uri
        }
      ]
    });
  }

  return facets;
}

return [{ json: {
  ...$json,
  bluesky: {
    text,
    facets: parseUrlFacets(text)
  }
} }];

