const session = $('Create Bluesky session').first().json;
const post = $json;
const rkey = typeof post.uri === 'string' ? post.uri.split('/').pop() : undefined;
return [{ json: {
  ok: true,
  platform: 'bluesky',
  uri: post.uri,
  cid: post.cid,
  url: session.handle && rkey ? 'https://bsky.app/profile/' + session.handle + '/post/' + rkey : undefined
} }];
